mapper.select:
SELECT d.dept_id, d.dept_name, d.leader_name, d.parent_id, d.description, d.status, d.reg_date, COUNT(v.volunteer_id) AS volunteer_count FROM erp_ministry_dept d LEFT JOIN erp_ministry_volunteer v ON d.dept_id = v.dept_id AND v.status = 'ACTIVE'
AND d.dept_name LIKE '%' || #{keyword} || '%'
GROUP BY d.dept_id, d.dept_name, d.leader_name, d.parent_id, d.description, d.status, d.reg_date ORDER BY d.dept_name LIMIT #{limit} OFFSET #{offset}

SELECT s.schedule_id, s.dept_id, COALESCE(s.dept_name, d.dept_name) AS dept_name, s.title, s.schedule_date, s.description, s.status, s.reg_date FROM erp_ministry_schedule s LEFT JOIN erp_ministry_dept d ON s.dept_id = d.dept_id
AND (s.title LIKE '%' || #{keyword} || '%' OR d.dept_name LIKE '%' || #{keyword} || '%')
ORDER BY s.schedule_date DESC LIMIT #{limit} OFFSET #{offset}

SELECT v.volunteer_id, v.member_id, v.member_name, v.dept_id, COALESCE(v.dept_name, d.dept_name) AS dept_name, v.role, v.start_date, v.end_date, v.status FROM erp_ministry_volunteer v LEFT JOIN erp_ministry_dept d ON v.dept_id = d.dept_id
AND (v.member_name LIKE '%' || #{keyword} || '%' OR d.dept_name LIKE '%' || #{keyword} || '%')
ORDER BY v.member_name LIMIT #{limit} OFFSET #{offset}

SELECT r.report_id, r.dept_id, COALESCE(r.dept_name, d.dept_name) AS dept_name, r.title, r.report_date, r.content, r.author_name, r.reg_date FROM erp_ministry_report r LEFT JOIN erp_ministry_dept d ON r.dept_id = d.dept_id
AND (r.title LIKE '%' || #{keyword} || '%' OR r.author_name LIKE '%' || #{keyword} || '%')
ORDER BY r.report_date DESC LIMIT #{limit} OFFSET #{offset}
